// ============================================================
// VERIFICACIÓN DE NÚMERO + EXTRACCIÓN DE MENSAJE
// Solo procesa mensajes de Luis Daniel: 526623538272
// ============================================================

const body = $input.first().json.body || {};

// --- Número autorizado de Luis Daniel ---
const NUMERO_AUTORIZADO = '526623538272';

// --- Extraer datos del payload de Baileys ---
// Baileys puede enviar el payload de varias formas según configuración
let from = '';
let mensaje = '';

// Estructura plana: { from, body }
if (body.from) {
  from = String(body.from).replace('@s.whatsapp.net', '').replace('@c.us', '').trim();
  mensaje = body.body || body.message || body.text || '';
}
// Estructura anidada: { data: { from, body } }
else if (body.data && body.data.from) {
  from = String(body.data.from).replace('@s.whatsapp.net', '').replace('@c.us', '').trim();
  mensaje = body.data.body || body.data.message || body.data.text || '';
}
// Estructura de evento de Baileys: { messages: [{ key: { remoteJid }, message: { conversation } }] }
else if (body.messages && body.messages.length > 0) {
  const msg = body.messages[0];
  from = String(msg.key?.remoteJid || '').replace('@s.whatsapp.net', '').replace('@c.us', '').trim();
  mensaje = msg.message?.conversation || msg.message?.extendedTextMessage?.text || '';
}

// --- Verificar que sea el número de Luis Daniel ---
if (from !== NUMERO_AUTORIZADO) {
  console.log(`Mensaje ignorado de número no autorizado: ${from}`);
  return [{
    json: {
      autorizado: false,
      from,
      razon: 'Número no autorizado — solo se procesan mensajes de Luis Daniel'
    }
  }];
}

// --- Mensaje vacío ---
if (!mensaje || mensaje.trim() === '') {
  return [{
    json: {
      autorizado: false,
      from,
      razon: 'Mensaje vacío — ignorado'
    }
  }];
}

// --- Limpiar y preparar el mensaje ---
const mensajeLimpio = mensaje.trim();

// --- Detectar comandos especiales ---
let comandoEspecial = null;
if (mensajeLimpio.toLowerCase().startsWith('/agenda')) comandoEspecial = 'agenda';
if (mensajeLimpio.toLowerCase().startsWith('/estado')) comandoEspecial = 'estado_mystic';
if (mensajeLimpio.toLowerCase().startsWith('/ayuda')) comandoEspecial = 'ayuda';

return [{
  json: {
    autorizado: true,
    from: NUMERO_AUTORIZADO,
    mensaje: mensajeLimpio,
    comando_especial: comandoEspecial,
    tenant_id: 'luis_daniel',
    canal: 'whatsapp_personal',
    timestamp: new Date().toISOString()
  }
}];

// ============================================================
// PREPARAR RESPUESTA FINAL
// Maneja respuesta del Brain IA o fallback si falla
// ============================================================

const brainResponse = $input.first().json;
const mensajeOriginal = $node['Verificar Número + Extraer Mensaje'].json.mensaje;

let respuesta = '';

// --- Verificar si el Brain IA respondió correctamente ---
if (brainResponse.error || !brainResponse) {
  // Fallback si el Brain IA no está disponible
  respuesta = `🤖 *MYSTIC Brain IA*\n\nEn este momento no puedo procesar tu consulta (Brain IA no disponible).\n\nTu pregunta fue: _"${mensajeOriginal}"_\n\nIntenta de nuevo en unos minutos o accede al panel: https://mystic.sonora.digital`;
} else {
  // Usar la respuesta del Brain IA
  const respuestaBrain = brainResponse.answer || brainResponse.response || brainResponse.message || brainResponse.result || JSON.stringify(brainResponse);
  const fuente = brainResponse.source || brainResponse.model || 'Brain IA';
  const confianza = brainResponse.confidence ? ` (confianza: ${Math.round(brainResponse.confidence * 100)}%)` : '';

  respuesta = `🧠 *MYSTIC Brain IA*${confianza}\n\n${respuestaBrain}\n\n_Powered by MYSTIC AI OS_`;
}

return [{
  json: {
    numero_destino: '526623538272',
    respuesta,
    brain_raw: brainResponse
  }
}];
